import type { Transaction, TransactionSpec } from '@codemirror/state';
import type { EditorView } from '@codemirror/view';
import { type MutableRefObject, useCallback } from 'react';
import { useErrorBoundary } from 'react-error-boundary';

/**
 * Encapsulates EditorView methods to apply ErrorBoundary aware error handling
 * on main methods
 * @internal
 */
export const useErrorAwareViewRef = (
  viewRef: MutableRefObject<EditorView | null>,
) => {
  const { showBoundary } = useErrorBoundary();

  const onError = useCallback(
    (error: unknown) => {
      showBoundary(error);
    },
    [showBoundary],
  );

  const dispatchFn = useCallback(
    (args: Transaction | TransactionSpec | TransactionSpec[]) => {
      // note: viewRef current is ensured non-null after the hook is called
      try {
        if (Array.isArray(args)) {
          viewRef.current?.dispatch(...args);
        } else {
          viewRef.current?.dispatch(args);
        }
      } catch (e) {
        onError(e);
      }
    },
    [viewRef, onError],
  );

  return {
    viewDispatch: dispatchFn,
  };
};
